import { 運筆 } from '../bi.js';
import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 畫指 } from '../bujian/zhi.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛護 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-6.9, 36.3], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.1], [6.9, 36.3], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        // 二拳當胸稍開，頭指相伸端對（指先落，拳覆其根——蔽法自斷，指端乃露）
        const 運 = 運筆(bi);
        運.衣(() => {
            畫指(運, [[-3.4, 35.0], [-1.5, 34.65], [-0.18, 34.55]], 0.95, 0.72, { 紋: true }, bi);
            畫指(運, [[3.4, 35.0], [1.5, 34.65], [0.18, 34.55]], 0.95, 0.72, { 紋: true }, bi);
        });
        側拳(bi, -5.1, 34.9, 0.48, 1.14);
        側拳(bi, 5.1, 34.9, -0.48, 1.14, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-6.5, 35.5, -5.9, 36.7, -5.1, 37.5], [-5.7, 35.1, -5.1, 36.3, -4.3, 37.1]], [-5.5, 36.4]);
            腕釧(bi, [[6.5, 35.5, 5.9, 36.7, 5.1, 37.5], [5.7, 35.1, 5.1, 36.3, 4.3, 37.1]], [5.5, 36.4]);
        });
    },
});
